def _render_markdown(value: str) -> str:
    value = (value or "").strip()
    if not value:
        return ""
    if markdown_lib:
        return markdown_lib.markdown(
            value,
            extensions=[
                "extra",
                "sane_lists",
                "toc",
                "smarty",
            ],
            output_format="html5",
        )
    return "<p>{}</p>".format("<br>".join(escape(value).splitlines()))


